beacons.example:
if (!('webbleIOS' in window)) throw new Error('Requires WebBLE companion app');

await window.webbleIOS.backgroundSync.registerBeaconScanning({
  filters: [{ services: ['battery_service'], namePrefix: 'Acme' }],
  cooldownSeconds: 30,
  template: {
